#include<bits/stdc++.h>
# define m 1000000007
using namespace std; 
int main(void){
    long long x,n,sum=0,sumsum=0,sumsumsum=0;
    cin>>n;
    while(n--){
    	cin>>x;
    	sum+=x;
        sumsum+=(x*x)%m;
        sumsumsum+=(((x*x)%m)*x)%m;
    }sum%=m;sumsum%=m;sumsumsum%=m;
    long long p=(((sum*sum)%m)*sum)%m,l=(3*sumsum*sum)%m,k=2*sumsumsum%m;
    cout<<((p-l+k)%m+m)%m;
    return false;
}
